function createConfigurableObject(prefix, useSSL, port, host, onClose, redisHost, redisPort, redisOptions) {
    // Input validation
    if (typeof prefix !== 'string') throw new TypeError('Prefix must be a string');
    if (typeof useSSL !== 'boolean') throw new TypeError('UseSSL must be a boolean');
    if (typeof port !== 'number' && port !== undefined) throw new TypeError('Port must be a number');
    if (typeof host !== 'string' && host !== undefined) throw new TypeError('Host must be a string');
    if (typeof onClose !== 'function') throw new TypeError('onClose must be a function');
    if (typeof redisHost !== 'string' && redisHost !== undefined) throw new TypeError('RedisHost must be a string');
    if (typeof redisPort !== 'number' && redisPort !== undefined) throw new TypeError('RedisPort must be a number');
    if (typeof redisOptions !== 'object' && redisOptions !== undefined) throw new TypeError('RedisOptions must be an object');

    // Sanitize the onClose callback to prevent arbitrary code execution
    const sanitizedOnClose = () => {
        try {
            onClose();
        } catch (error) {
            console.error('Error executing onClose callback:', error);
        }
    };

    const config = {
        prefix: prefix || '',
        useSSL: useSSL || false,
        port: port || 8080,
        host: host || 'localhost',
        onClose: sanitizedOnClose,
        redis: {
            host: redisHost || 'localhost',
            port: redisPort || 6379,
            options: Object.assign({}, redisOptions || {}) // Clone to avoid external modifications
        }
    };

    config.createConnection = () => {
        console.log(`Creating connection to ${config.host}:${config.port}`);
        // Simulate connection creation
        setTimeout(() => {
            console.log('Simulated connection closed');
            config.onClose();
        }, 2000);
    };

    return config;
}
```

